DROP TABLE IF EXISTS `loan_portfolio`;

CREATE TABLE `loan_portfolio` (
  `Age` int DEFAULT NULL,
  `Income` decimal(10,2) DEFAULT NULL,
  `LoanAmount` decimal(10,2) DEFAULT NULL,
  `CreditScore` decimal(10,2) DEFAULT NULL,
  `YearsExperience` int DEFAULT NULL,
  `Gender` varchar(20) DEFAULT NULL,
  `Education` varchar(50) DEFAULT NULL,
  `City` varchar(100) DEFAULT NULL,
  `EmploymentType` varchar(50) DEFAULT NULL,
  `LoanApproved` tinyint DEFAULT NULL,
  `LoanToIncome` decimal(15,6) DEFAULT NULL,
  `IncomeGroup` varchar(20) DEFAULT NULL,
  `CreditCategory` varchar(20) DEFAULT NULL,
  `ExperienceGroup` varchar(20) DEFAULT NULL,
  `RiskLevel` varchar(20) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

LOCK TABLES `loan_portfolio` WRITE;

